@using sv_10887b16308647158bbaa9ea440fba5c.Models
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-3">Product Catalog</h3>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @_error
    </div>
}
else
{
    <div class="row">
        <!-- Filter Sidebar -->
        <div class="col-md-3">
            <ProductFilterPanel Categories="@_categories"
                                OnFilterApplied="HandleFilterApplied"
                                OnFilterCleared="HandleFilterCleared" />
        </div>

        <!-- Main Content -->
        <div class="col-md-9">
            @if (_isLoading)
            {
                <div class="d-flex justify-content-center align-items-center" style="min-height: 200px;">
                    <div class="spinner-border text-primary" role="status">
                        <span class="visually-hidden">Loading...</span>
                    </div>
                </div>
            }
            else if (_result is null || _result.Items.Count == 0)
            {
                <div class="alert alert-info" role="alert">
                    No products found matching your criteria. Try adjusting your filters.
                </div>
            }
            else
            {
                <ProductToolbar SortBy="@_sortBy"
                                TotalCount="@_result.TotalCount"
                                Page="@_result.Page"
                                PageSize="@_result.PageSize"
                                OnSortChanged="HandleSortChanged" />

                <ProductGrid Products="@_result.Items"
                             OnProductSelected="HandleProductSelected"
                             OnAddToCart="HandleAddToCart" />

                @if (TotalPages > 1)
                {
                    <div class="mt-4">
                        <CatalogPagination CurrentPage="@_currentPage"
                                           TotalPages="@TotalPages"
                                           OnPageChanged="HandlePageChanged" />
                    </div>
                }
            }
        </div>
    </div>
}

@code {
    /// <summary>
    /// Raised when a product card is clicked so the parent can navigate to a detail page.
    /// </summary>
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private const int DefaultPageSize = 9;

    private List<string>? _categories;
    private PagedResult<Product>? _result;
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private bool _isLoading = true;
    private string? _error;

    private int TotalPages => _result is null || _result.PageSize == 0
        ? 0
        : (int)Math.Ceiling((double)_result.TotalCount / _result.PageSize);

    protected override async Task OnInitializedAsync()
    {
        try
        {
            _categories = await ProductService.GetCategoriesAsync();
            await LoadProducts();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
            _isLoading = false;
        }
    }

    private async Task LoadProducts()
    {
        _isLoading = true;
        try
        {
            _result = await ProductService.SearchAsync(_filter, _sortBy, _currentPage, DefaultPageSize);
            _error = null;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _isLoading = false;
        }
    }

    private async Task HandleFilterApplied(ProductFilter filter)
    {
        _filter = filter;
        _currentPage = 1;
        await LoadProducts();
    }

    private async Task HandleFilterCleared()
    {
        _filter = new ProductFilter(null, null, null, false);
        _currentPage = 1;
        await LoadProducts();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _currentPage = 1;
        await LoadProducts();
    }

    private async Task HandlePageChanged(int page)
    {
        _currentPage = page;
        await LoadProducts();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder for cart functionality
        return Task.CompletedTask;
    }
}
"}

