+            _categories = await ProductService.GetCategoriesAsync();
+            await LoadProducts();
+        }
+        catch (Exception ex)
+        {
+            _error = ex.Message;
+            _isLoading = false;
+        }
+    }
+
+    private async Task LoadProducts()
+    {
+        _isLoading = true;
+        try
+        {
+            _result = await ProductService.SearchAsync(_filter, _sortBy, _currentPage, DefaultPageSize);
+            _error = null;
+        }
+        catch (Exception ex)
+        {
+            _error = ex.Message;
+        }
+        finally
+        {
+            _isLoading = false;
+        }
+    }
+
+    private async Task HandleFilterApplied(ProductFilter filter)
+    {
+        _filter = filter;
+        _currentPage = 1;
+        await LoadProducts();
+    }
+
+    private async Task HandleFilterCleared()
+    {
+        _filter = new ProductFilter(null, null, null, false);
+        _currentPage = 1;
+        await LoadProducts();
+    }
+
+    private async Task HandleSortChanged(string sortBy)
+    {
+        _sortBy = sortBy;
+        _currentPage = 1;
+        await LoadProducts();
+    }
+
+    private async Task HandlePageChanged(int page)
+    {
+        _currentPage = page;
+        await LoadProducts();
+    }
+
+    private async Task HandleProductSelected(Product product)
+    {
+        await OnProductSelected.InvokeAsync(product);
+    }
+
